input.script:
export default async function({ execution_id }) {
  const problem = await fetch(`/api/v2/problems/${event()['event.id']}`);
  const problemJson = await problem.json();
  const startTime = new Date(problemJson.startTime);
  const from = new Date(startTime.getTime() - 5 * 60 * 1000).toISOString();
  const to = new Date(startTime.getTime() + 15 * 60 * 1000).toISOString();
  return {
    problemId: problemJson.problemId,
    displayId: problemJson.displayId,
    title: problemJson.title,
    entityId: problemJson.affectedEntities?.[0]?.entityId?.id || 'unknown',
    entityName: problemJson.affectedEntities?.[0]?.name || 'unknown',
    from: from,
    to: to,
    startTime: startTime.toISOString()
  };
}

